const agentOutput = $input.first().json.output;

// Parse JSON — strip markdown fences if agent wrapped it
let parsed;
try {
  parsed = JSON.parse(agentOutput);
} catch (e) {
  const cleaned = agentOutput.replace(/```json\n?|\n?```/g, '').trim();
  parsed = JSON.parse(cleaned);
}

const generatedAt = new Date().toISOString();

return parsed.captions.map(c => ({
  json: {
    ID: c.id,
    Vibe: c.vibe,
    Model: c.model,
    Caption: c.caption_text,
    Hashtags: c.hashtags,
    Generated_At: generatedAt
  }
}));
